{
  "mode": "io",
  "tests": [
    {
      "name": "valid_manual_payment",
      "input": "{\"challengeId\": 30096991, \"submitterId\": 12345, \"amount\": 100.00}",
      "output": "{\"status\": \"success\", \"message\": \"Payment saved successfully\"}",
      "notes": "Tests a valid manual payment scenario."
    },
    {
      "name": "missing_amount",
      "input": "{\"challengeId\": 30096991, \"submitterId\": 12345}",
      "output": "{\"status\": \"error\", \"message\": \"Amount is required\"}",
      "notes": "Tests the case where the amount is missing."
    },
    {
      "name": "invalid_challenge_id",
      "input": "{\"challengeId\": 99999, \"submitterId\": 12345, \"amount\": 100.00}",
      "output": "{\"status\": \"error\", \"message\": \"Challenge not found\"}",
      "notes": "Tests the case where the challenge ID does not exist."
    },
    {
      "name": "negative_amount",
      "input": "{\"challengeId\": 30096991, \"submitterId\": 12345, \"amount\": -50.00}",
      "output": "{\"status\": \"error\", \"message\": \"Amount must be positive\"}",
      "notes": "Tests the case where a negative amount is provided."
    },
    {
      "name": "duplicate_payment",
      "input": "{\"challengeId\": 30096991, \"submitterId\": 12345, \"amount\": 100.00}",
      "output": "{\"status\": \"error\", \"message\": \"Payment already exists\"}",
      "notes": "Tests the scenario where a duplicate payment is attempted."
    },
    {
      "name": "valid_payment_for_reviewer",
      "input": "{\"challengeId\": 30096991, \"reviewerId\": 54321, \"amount\": 150.00}",
      "output": "{\"status\": \"success\", \"message\": \"Payment saved successfully\"}",
      "notes": "Tests a valid manual payment scenario for a reviewer."
    },
    {
      "name": "invalid_submitter_id",
      "input": "{\"challengeId\": 30096991, \"submitterId\": 99999, \"amount\": 100.00}",
      "output": "{\"status\": \"error\", \"message\": \"Submitter not found\"}",
      "notes": "Tests the case where the submitter ID does not exist."
    },
    {
      "name": "empty_input",
      "input": "{}",
      "output": "{\"status\": \"error\", \"message\": \"Challenge ID, submitter/reviewer ID, and amount are required\"}",
      "notes": "Tests the case where no input is provided."
    }
  ],
  "assumptions": "Challenge IDs and user IDs are valid integers. Amounts are positive decimal numbers.",
  "notes": "Ensure to check the logs for any warnings or errors during the tests."
}
